 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
 7	import { getHostname } from '@kubevirt-utils/resources/vm';
 8	import {
 9	  ClipboardCopy,
10	  ClipboardCopyVariant,
11	  DescriptionList,
12	  Divider,
13	} from '@patternfly/react-core';
14	
15	import './virtual-machines-overview-tab-network-fqdn.scss';
16	
17	type VirtualMachinesOverviewTabNetworkFQDN = {
18	  vm: V1VirtualMachine;
19	};
20	
21	const VirtualMachinesOverviewTabNetworkFQDN: FC<VirtualMachinesOverviewTabNetworkFQDN> = ({
22	  vm,
23	}) => {
24	  const { t } = useKubevirtTranslation();
25	
26	  if (!vm) return null;
27	
28	  return (
29	    <>
30	      <Divider />
31	      <DescriptionList className="pf-v6-c-description-list" isHorizontal>
32	        <VirtualMachineDescriptionItem
33	          descriptionData={
34	            <ClipboardCopy
35	              clickTip={t('Copied')}
36	              hoverTip={t('Copy to clipboard')}
37	              variant={ClipboardCopyVariant.inlineCompact}
38	            >
39	              {`${getName(vm) || getHostname(vm)}.headless.${getNamespace(vm)}.svc.cluster.local`}
40	            </ClipboardCopy>
41	          }
42	          className="VirtualMachinesOverviewTabNetworkFQDN--main"
43	          descriptionHeader={t('Internal FQDN')}
44	          isPopover
45	        />
46	      </DescriptionList>
47	    </>
48	  );
49	};
50	
51	export default VirtualMachinesOverviewTabNetworkFQDN;

